class Node:
    def __init__(self, data):
        self.data = data
        self.next = None


class CircularLinkedList:
    def __init__(self):
        self.head = None
        self.tail = None

    def is_empty(self):
        return self.head is None

    def append(self, data):
        new_node = Node(data)
        if self.is_empty():
            self.head = new_node
            self.tail = new_node
            new_node.next = self.head  # Points to itself
        else:
            self.tail.next = new_node
            new_node.next = self.head
            self.tail = new_node

    def prepend(self, data):
        new_node = Node(data)
        if self.is_empty():
            self.head = new_node
            self.tail = new_node
            new_node.next = self.head
        else:
            new_node.next = self.head
            self.tail.next = new_node
            self.head = new_node

    def delete(self, data):
        if self.is_empty():
            return

        # Special case: Deleting the only node
        if self.head == self.tail:
            if self.head.data == data:
                self.head = None
                self.tail = None
            return

        current = self.head
        prev = self.tail  # Initialize prev to tail, as tail points to head

        # Traverse the list to find the node to delete and its previous node
        # Stop when we loop back to head (meaning data not found)
        node_found = False
        while True:
            if current.data == data:
                node_found = True
                break
            prev = current
            current = current.next
            if current == self.head:  # Completed a full cycle, data not found
                break

        if not node_found:
            return  # Data not found in the list

        # If the node to delete is the head
        if current == self.head:
            self.head = self.head.next
            self.tail.next = self.head  # Tail's next must point to the new head
        # If the node to delete is the tail (and not also the head, which is handled above)
        elif current == self.tail:
            prev.next = self.head  # The node before tail now points to head
            self.tail = prev      # The node before tail becomes the new tail
        # If the node to delete is in the middle
        else:
            prev.next = current.next  # Bypass the current node

    def display(self):
        if self.is_empty():
            print("List is empty")
            return

        elements = []
        current = self.head
        while True:
            elements.append(str(current.data))
            current = current.next
            if current == self.head:
                break
        print(" -> ".join(elements) + " (-> HEAD)")
